solution_code:
#include <iostream>

enum Month
{
    january, february, march, april, may, june,
    july, august, september, october, november, december
};

int main()
{
    int index{};
    std::cin >> index;

    Month month{ static_cast<Month>(index) };
    int quarter{ month / 3 + 1 };

    std::cout << "Quarter " << quarter << '\n';

    return 0;
}

